#!/usr/bin/env node
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const OUT = path.join(__dirname, '../../book-packages/cant-hurt-me.modern.json');

function p(text) { return { type: 'paragraph', text }; }
function b(text, detail) { return { type: 'bullet', text, detail }; }
function ex(id, title, ctx, scenario, whatToDo, whyItMatters) {
  return { exampleId: id, title, contexts: [ctx], scenario, whatToDo: [whatToDo], whyItMatters };
}
function q(id, prompt, choices, correctIndex) {
  return { questionId: id, prompt, choices, correctIndex };
}

